field.expression:
select SEC_TO_TIME(sum(FF.minutos)) from (select F1.fecha,
@egr:= CONVERT((SELECT H.egreso from HORARIOHIST as H where H.desdeFecha <= F1.fecha and H.dia = DAYOFWEEK(F1.fecha) order by H.desdeFecha DESC limit 1), CHAR) as "egr", @ing:= CONVERT((SELECT H.ingreso from HORARIOHIST as H where H.desdeFecha <= F1.fecha and H.dia = DAYOFWEEK(F1.fecha) order by H.desdeFecha DESC limit 1), CHAR) as "ing",
@h1:= CONVERT((select H1.hora from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__] and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.hora limit 0, 1), CHAR) as "h1", @h2:= CONVERT((select H1.hora from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__] and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.hora limit 1, 1), CHAR) as "h2", @h3:= CONVERT((select H1.hora from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__] and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.hora limit 2, 1), CHAR) as "h3", @h4:= CONVERT((select H1.hora from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__] and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.hora limit 3, 1), CHAR) as "h4",
ifnull( time_to_sec( timediff( case when @egr = @ing then @egr when @h2 > @egr then @egr else @h2 end , case when @egr = @ing then @ing when @h1 < @ing then @ing else @h1 end )), 0) + ifnull( time_to_sec( timediff( case when @h4 > @egr then @egr else @h4 end , case when @h4 < @ing then @ing else @h3 end )), 0)
as "minutos"
from GEN_CALENDAR as F1 left join FERIADOS ON FERIADOS.idFeriado = F1.fecha where F1.fecha >= '[__desde__]' and F1.fecha <= '[__hasta__]' and isnUll(FERIADOS.idFeriado)) as FF

                    select SEC_TO_TIME(sum(case when FF.minutos_trabajados <= FF.minutos_proyeccion then FF.minutos_trabajados else FF.minutos_proyeccion end)) from 
                    (select F1.fecha,

@egr:= CONVERT((SELECT H.egreso from HORARIOHIST as H  where H.desdeFecha <= F1.fecha and H.dia = DAYOFWEEK(F1.fecha) order by H.desdeFecha DESC limit 1), CHAR) as "egr",
@ing:= CONVERT((SELECT H.ingreso from HORARIOHIST as H where H.desdeFecha <= F1.fecha and H.dia = DAYOFWEEK(F1.fecha) order by H.desdeFecha DESC limit 1), CHAR) as "ing",

@h1:= CONVERT((select H1.crc from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.crc  limit 0, 1), CHAR) as "h1",
@h2:= CONVERT((select H1.crc from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.crc  limit 1, 1), CHAR) as "h2",
@h3:= CONVERT((select H1.crc from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.crc  limit 2, 1), CHAR) as "h3",
@h4:= CONVERT((select H1.crc from FICHADAS as H1 left join FERIADOS ON FERIADOS.idFeriado = H1.fecha where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= F1.fecha order by fechaDesde DESC limit 1) and H1.fecha = F1.fecha and H1.borrado = 0 order by H1.crc  limit 3, 1), CHAR) as "h4",

ifnull( time_to_sec( timediff( @h2, @h1 ) ), 0)
+
ifnull( time_to_sec( timediff( @h4 , @h3 )), 0)

as "minutos_trabajados",

ifnull( time_to_sec( timediff( @egr, @ing ) ), 0)

as "minutos_proyeccion"

             from GEN_CALENDAR as F1 left join FERIADOS ON FERIADOS.idFeriado = F1.fecha
        where
                          F1.fecha  >= '[__desde__]' and
                          F1.fecha  <= '[__hasta__]' and
        isnUll(FERIADOS.idFeriado)) as FF
